/*
  Page table structure:
  v[0] --> Valid : Indicates whether the physical page has been allocated in memory. If the V bit of a page is 0, access to the page will cause a page fault exception.
  R[1] --> Readable
  W[2] --> Writable
  X[3] --> Executable
           -------------------------------------------------
            X | W | R | Meaning
           -------------------------------------------------
            0 | 0 | 0 | Pointer to next level of page table
            0 | 0 | 1 | Read-only page
            0 | 1 | 0 | Reserved for future use
            0 | 1 | 1 | Read-write page
            1 | 0 | 0 | Execute-only page
            1 | 0 | 1 | Read-execute page
            1 | 1 | 0 | Reserved for future page
            1 | 1 | 1 | Read-write-execute page

   U[4] --> User : 1’b0: indicates that the page is inaccessible in U-mode, 1’b1: indicates that the page is accessible in U-mode.
   G[5] --> Global :1’b0: indicates that the page is non-shareable and that the ASID is exclusive, 1’b1: indicates that the page is shareable.
   A[6] --> Accessed : When the A bit is 1, it indicates that the page is accessed. When the A bit is 0, it indicates that the page is not accessed
   D[7] --> Dirty : 1’b0: indicates that data has not been written/cannot be written to the page, 1’b1: indicates that data has been written/can be written to the page.
  RSW[8..9] --> Reserved for Software: A bit reserved for software to implement custom page table features.
  PPN0[10..18] --> indicates the PPN corresponding to level0 of page table
  PPN1[19..27] --> indicates the PPN corresponding to level1 of page table
  PPN2[28..37] --> indicates the PPN corresponding to level2 of page table (root PTE)
      [38..58] --> not used, set to 0.
    T[59] --> Trustable : 1’b0: Non-trustable, 1’b1: Trustable
     [60] --> not used, set to 0.
    B[61] --> Buffer : 1’b0: Non-bufferable, 1’b1: Bufferable
    C[62] --> Cacheable : 1’b0: Non-cacheable, 1’b1: Cacheable
   SO[63] --> Strong order : 1’b0: no strong order (Normal-memory), 1’b1: strong order (Device)
*/

/*******************************************************************************************
  \brief  
  
  \param  
  
  \return 
********************************************************************************************/
.section .rodata
.type mmu_page_table_level_2, @object
.align 12
.globl mmu_page_table_level_2

mmu_page_table_level_2:

.quad (1 << 63) | (0 << 62) | (0 << 61) | (1 << 59) | ((0x00000000 >> 12) << 10) | (0x0F << 4) | (3 << 1) | (1 << 0) /* VA: 0x0000_0000 - 0x3FFF_FFFF --> PA: 0x0000_0000 - 0x3FFF_FFFF : leaf table entry (Device, non-cacheable and RW) */
.quad (1 << 63) | (0 << 62) | (0 << 61) | (1 << 59) | ((0x40000000 >> 12) << 10) | (0x0F << 4) | (3 << 1) | (1 << 0) /* VA: 0x4000_0000 - 0x7FFF_FFFF --> PA: 0x4000_0000 - 0x7FFF_FFFF : leaf table entry (Device, non-cacheable and RW) */
.quad MMU_PT_LEVEL_1_0x8000_0000                                                                                     /* VA: 0x8000_0000 - 0xBFFF_FFFF --> PA: 0x8000_0000 - 0xBFFF_FFFF : level 1 page table */
.quad MMU_PT_LEVEL_1_0xC000_0000                                                                                     /* VA: 0xC000_0000 - 0xFFFF_FFFF --> PA: 0xC000_0000 - 0xFFFF_FFFF : level 1 page table */
.fill 508, 8, 0   /* Fill the rest with invalid PTE entries */

.size mmu_page_table_level_2, .-mmu_page_table_level_2

